# -*- coding: utf-8 -*-
"""
TJK tam akış tek dosya - SELF HEAL KOSU LINK FIX sürümü.

Düzeltme:
- Kocaeli gibi bazı şehirlerde idman linkleri eksik yakalanmasın diye
  kosu_linklerini_topla fonksiyonu güçlendirildi.
- Sadece "İdman Bilgileri" exact textine güvenmez.
- Sayfadaki href / onclick / data-url içindeki KosuKodu değerlerini de yakalar.
- Lazy yüklenen butonlar için scroll + çok turlu toplama yapar.

Çalıştırma:
    python3 tjk_tum_akis_main_SELF_HEAL_KOSU_LINK_FIX.py
"""

from __future__ import annotations

import builtins
from pathlib import Path

EXCEL_NAME = 'tjk_ULTRA_MESAFELI_YARIN.xlsx'

SCRAPER_CODE = 'from selenium import webdriver\nfrom selenium.webdriver.common.by import By\nfrom selenium.webdriver.chrome.options import Options\nfrom selenium.webdriver.support.ui import WebDriverWait\nfrom selenium.webdriver.support import expected_conditions as EC\nfrom selenium.common.exceptions import TimeoutException, WebDriverException, StaleElementReferenceException, InvalidSessionIdException\n\nfrom urllib.parse import urlparse, parse_qs\nimport pandas as pd\nimport urllib.parse\nimport time\nimport re\nfrom datetime import datetime, timedelta\nfrom pathlib import Path\n\n\n# =========================\n# AYARLAR\n# =========================\n\nTEST_MODU = False\nSON_GALOP_LIMIT = 100000   # SINIRSIZ (eski: 10) — yalnız SON GALOP listesini etkiler\nHEADLESS = True\nEXCEL_NAME = "tjk_ULTRA_MESAFELI_YARIN.xlsx"\nHAM_SHEET = "ham veri"\n\n# Veri kaçırmayı azaltan ayarlar\nPAGE_TIMEOUT = 45\nWAIT_TIMEOUT = 18\nAT_RETRY = 3\nKOSU_RETRY = 2\nSHORT_SLEEP = 0.8\nCITY_SLEEP = 1.5\nDRIVER_REFRESH_EVERY_HORSES = 25\nMAX_DRIVER_RESTARTS_PER_CITY = 8\n\nTURK_SEHIRLER = [\n    "Şanlıurfa", "Diyarbakır", "Elazığ", "Adana", "Ankara",\n    "Antalya", "İzmir", "Bursa", "Kocaeli", "İstanbul"\n]\n\nMESAFELER = [400, 600, 800, 1000, 1200, 1400]\n\nGUNLER = {\n    0: "Pazartesi", 1: "Salı", 2: "Çarşamba", 3: "Perşembe",\n    4: "Cuma", 5: "Cumartesi", 6: "Pazar"\n}\n\nAYLAR = {\n    1: "Ocak", 2: "Şubat", 3: "Mart", 4: "Nisan", 5: "Mayıs", 6: "Haziran",\n    7: "Temmuz", 8: "Ağustos", 9: "Eylül", 10: "Ekim", 11: "Kasım", 12: "Aralık"\n}\n\n\n# =========================\n# DRIVER\n# =========================\n\ndef make_driver():\n    options = Options()\n\n    if HEADLESS:\n        options.add_argument("--headless=new")\n\n    options.add_argument("--disable-gpu")\n    options.add_argument("--disable-dev-shm-usage")\n    options.add_argument("--no-sandbox")\n    options.add_argument("--window-size=1500,1100")\n    options.add_argument("--blink-settings=imagesEnabled=false")\n    options.add_argument("--disable-notifications")\n    options.add_argument("--disable-popup-blocking")\n\n    prefs = {\n        "profile.managed_default_content_settings.images": 2,\n        "profile.default_content_setting_values.notifications": 2,\n    }\n    options.add_experimental_option("prefs", prefs)\n\n    driver = webdriver.Chrome(options=options)\n    driver.set_page_load_timeout(PAGE_TIMEOUT)\n    return driver\n\n\ndef wait_body(driver, timeout=WAIT_TIMEOUT):\n    WebDriverWait(driver, timeout).until(\n        EC.presence_of_element_located((By.TAG_NAME, "body"))\n    )\n\n\ndef wait_table(driver, timeout=WAIT_TIMEOUT):\n    WebDriverWait(driver, timeout).until(\n        EC.presence_of_element_located((By.TAG_NAME, "table"))\n    )\n\n\ndef safe_get(driver, url, timeout=WAIT_TIMEOUT):\n    driver.get(url)\n    wait_body(driver, timeout)\n    time.sleep(SHORT_SLEEP)\n\n\nclass DriverDiedError(Exception):\n    pass\n\n\ndef is_driver_dead_error(e):\n    msg = str(e).lower()\n    return (\n        isinstance(e, InvalidSessionIdException)\n        or "invalid session id" in msg\n        or "session deleted" in msg\n        or "disconnected" in msg\n        or "chrome not reachable" in msg\n        or "no such window" in msg\n        or "target window already closed" in msg\n    )\n\n\ndef restart_driver(driver, reason=""):\n    if reason:\n        print(f"  >>> DRIVER YENİLENİYOR: {reason}")\n    try:\n        driver.quit()\n    except Exception:\n        pass\n    time.sleep(1.0)\n    return make_driver()\n\n\n# =========================\n# YARDIMCI\n# =========================\n\ndef program_tarihi():\n    # Hedef gün gun_ayar.py\'den (OFFSET): gerçek bugün + OFFSET. Tek yerden ayarlanır.\n    try:\n        from gun_ayar import OFFSET as _g\n    except Exception:\n        _g = 0\n    try:\n        from gun_ayar import hedef_gun as _hg\n        return _hg()\n    except Exception:\n        return datetime.now() + timedelta(days=_g)\n\n\ndef bugun_baslik_tarihi():\n    # Eski isim bırakıldı; ama artık yarının tarihini basar.\n    d = program_tarihi()\n    return f"{GUNLER[d.weekday()]} {{sehir}} {{kosu_no}}. Koşu Galoplar ({d.day} {AYLAR[d.month]} {d.year})"\n\n\ndef beklenen_program_tarihi_token():\n    d = program_tarihi()\n    return d.strftime("%d/%m/%Y")\n\n\ndef temizle(x):\n    return "" if x is None else str(x).strip()\n\n\ndef galop_saniye_cevir(value):\n    s = temizle(value)\n    if s == "" or "kenter" in s.lower():\n        return ""\n\n    s = s.replace(":", ".").replace(",", ".")\n    parts = s.split(".")\n\n    try:\n        if len(parts) >= 3:\n            return int(parts[0]) * 60 + int(parts[1]) + int(parts[2]) / (10 ** len(parts[2]))\n        return float(s)\n    except Exception:\n        return ""\n\n\ndef derece_mi(x):\n    return bool(re.fullmatch(r"\\d{1,2}[.:,]\\d{2}[.:,]\\d{2}", temizle(x)))\n\n\ndef tarih_token_mi(x):\n    return bool(re.fullmatch(r"\\d{1,2}[./]\\d{1,2}[./]\\d{4}", temizle(x)))\n\n\ndef irk_duzelt(irk):\n    s = temizle(irk).lower()\n    if "ingiliz" in s or "i̇ngiliz" in s:\n        return "İngilizler"\n    if "arap" in s:\n        return "Araplar"\n    return temizle(irk)\n\n\ndef normalize_pist(sehir, pist_raw):\n    pist = temizle(pist_raw)\n    t = pist.lower()\n    t2 = t.replace("ı", "i")\n\n    pist_durum = "Nemli" if "nemli" in t2 else ""\n\n    has_ic = ("iç" in t) or ("ic" in t2)\n    has_kum = "kum" in t2\n    has_sentetik = "sentetik" in t2\n    has_cim = ("çim" in t) or ("cim" in t2)\n\n    if sehir in ["İstanbul", "Antalya"]:\n        if has_sentetik:\n            return "Kum", "Normal", pist_durum\n        if has_kum or has_ic:\n            return "Kum", "İç", pist_durum\n\n    if has_ic:\n        return "Kum", "İç", pist_durum\n    if has_kum or has_sentetik:\n        return "Kum", "Normal", pist_durum\n    if has_cim:\n        return "Çim", "Normal", pist_durum\n    if pist == "":\n        return "", "Normal", pist_durum\n    return pist, "Normal", pist_durum\n\n\ndef header_mesafe_indexleri(headers):\n    """\n    TJK idman tablosundaki gerçek kolon indexlerini okur.\n    KRİTİK: Mesafe saniyeden tahmin edilmez. Derece hangi başlık kolonundaysa oraya yazılır.\n    """\n    sonuc = {}\n    for idx, h in enumerate(headers):\n        h2 = temizle(h).lower().replace(" ", "")\n        m = re.search(r"(400|600|800|1000|1200|1400)m?", h2)\n        if not m:\n            continue\n        mesafe = int(m.group(1))\n        if mesafe in MESAFELER:\n            sonuc[idx] = mesafe\n    return sonuc\n\n\ndef tablo_headerlarini_al(table):\n    """Header hücrelerini boşları silmeden alır; index kayması olmasın diye şart."""\n    rows = table.find_elements(By.TAG_NAME, "tr")\n    if not rows:\n        return []\n\n    first = rows[0]\n    ths = first.find_elements(By.TAG_NAME, "th")\n    if ths:\n        return [temizle(th.text) for th in ths]\n\n    cells = first.find_elements(By.TAG_NAME, "td")\n    return [temizle(c.text) for c in cells]\n\n\ndef mesafeleri_basliga_gore_yerlestir(values, mesafe_indexleri):\n    raw = {m: "" for m in MESAFELER}\n    sn = {m: "" for m in MESAFELER}\n\n    # KESİN KURAL:\n    # Boş hücreler korunmuş values listesinde derece hangi indexteyse,\n    # o indexin TJK başlığındaki mesafesine yazılır. Tahmin yok.\n    if not mesafe_indexleri:\n        return raw, sn\n\n    for idx, value in enumerate(values):\n        derece = temizle(value)\n        if not derece_mi(derece):\n            continue\n        mesafe = mesafe_indexleri.get(idx)\n        if mesafe not in MESAFELER:\n            continue\n        raw[mesafe] = derece\n        sn[mesafe] = galop_saniye_cevir(derece)\n\n    return raw, sn\n\n\ndef gercek_kosu_no_bul(driver, yedek_no):\n    try:\n        text = driver.find_element(By.TAG_NAME, "body").text\n        m = re.search(r"(\\d+)\\.\\s*Koşu", text, re.IGNORECASE)\n        if m:\n            return m.group(1)\n    except Exception:\n        pass\n    return str(yedek_no)\n\n\ndef sekli_internetten_cek(values):\n    vals = [temizle(v) for v in values if temizle(v)]\n    joined = " | ".join(vals).lower()\n    if "kenter" in joined:\n        return "KENTER"\n\n    derece_indices = [i for i, v in enumerate(vals) if derece_mi(v)]\n    tarih_indices = [i for i, v in enumerate(vals) if tarih_token_mi(v)]\n\n    if derece_indices and tarih_indices:\n        last_derece_idx = max(derece_indices)\n        possible_tarih = [i for i in tarih_indices if i > last_derece_idx]\n        if possible_tarih:\n            first_tarih_idx = min(possible_tarih)\n            for i in range(last_derece_idx + 1, first_tarih_idx):\n                val = temizle(vals[i])\n                if val:\n                    return val\n    return ""\n\n\ndef tarih_cek(values):\n    for v in values:\n        if tarih_token_mi(v):\n            return temizle(v)\n    return ""\n\n\ndef galop_sehir_pist_tip_jokey_cek(values):\n    vals = [temizle(v) for v in values if temizle(v)]\n    tarih = tarih_cek(vals)\n    if tarih == "":\n        return "", "", "", ""\n\n    try:\n        ti = vals.index(tarih)\n    except ValueError:\n        return "", "", "", ""\n\n    sehir_index = -1\n    galop_sehir = ""\n\n    for i in range(ti + 1, len(vals)):\n        for s in TURK_SEHIRLER:\n            if vals[i].lower() == s.lower():\n                sehir_index = i\n                galop_sehir = s\n                break\n        if sehir_index != -1:\n            break\n\n    if sehir_index == -1:\n        return "", "", "", ""\n\n    kalan = vals[sehir_index + 1:]\n    pist_tokens = []\n    galop_tipi = ""\n    jokey = ""\n\n    for idx, token in enumerate(kalan):\n        tl = token.lower()\n        if tl in ["galop", "sprint"]:\n            galop_tipi = token\n            if idx + 1 < len(kalan):\n                jokey = kalan[idx + 1]\n            break\n        if tl == "detay":\n            break\n        pist_tokens.append(token)\n\n    joined = " ".join(pist_tokens)\n    j = joined.lower().replace("ı", "i")\n\n    if "sentetik" in j:\n        pist = "Sentetik"\n    elif "iç" in joined.lower() or "ic" in j:\n        pist = "Kum-İç"\n    elif "kum" in j:\n        pist = "Kum"\n    elif "çim" in joined.lower() or "cim" in j:\n        pist = "Çim"\n    else:\n        pist = joined.strip()\n\n    return galop_sehir, pist, galop_tipi, jokey\n\n\ndef galop_satiri_coz(values, sehir_adi, kosu_adi, kosu_kodu, horse_name, at_no, galop_no, mesafe_indexleri=None):\n    # values boş hücreleri korur. Metadata için ayrıca boşsuz kopya kullanıyoruz.\n    values_raw = [temizle(v) for v in values]\n    vals = [v for v in values_raw if v]\n    mesafe_indexleri = mesafe_indexleri or {}\n\n    at_adi = vals[0] if len(vals) > 0 else horse_name\n    irk = vals[1] if len(vals) > 1 else ""\n    cinsiyet = vals[2] if len(vals) > 2 else ""\n    yas = vals[3] if len(vals) > 3 else ""\n\n    tarih = tarih_cek(vals)\n    sekli = sekli_internetten_cek(vals)\n    galop_sehir, pist, galop_tipi, jokey = galop_sehir_pist_tip_jokey_cek(vals)\n\n    if galop_sehir == "":\n        galop_sehir = sehir_adi\n\n    raw_mesafe, sn_mesafe = mesafeleri_basliga_gore_yerlestir(values_raw, mesafe_indexleri)\n    zemin, pist_turu, pist_durum = normalize_pist(galop_sehir, pist)\n    mesafe_kaynak = "TJK_HEADER_INDEX" if mesafe_indexleri else "HEADER_YOK_MESAFE_YAZILMADI"\n\n    return {\n        "Koşu": kosu_adi,\n        "At No": at_no,\n        "Irk": irk_duzelt(irk),\n        "Tarih": tarih,\n        "Şehir": galop_sehir,\n        "400": raw_mesafe[400], "400 sn": sn_mesafe[400],\n        "600": raw_mesafe[600], "600 sn": sn_mesafe[600],\n        "800": raw_mesafe[800], "800 sn": sn_mesafe[800],\n        "1000": raw_mesafe[1000], "1000 sn": sn_mesafe[1000],\n        "1200": raw_mesafe[1200], "1200 sn": sn_mesafe[1200],\n        "1400": raw_mesafe[1400], "1400 sn": sn_mesafe[1400],\n        "Şekli": sekli,\n        "Zemin": zemin,\n        "Pist Türü": pist_turu,\n        "Pist Durum": pist_durum,\n        "KosuKodu": kosu_kodu,\n        "At": horse_name,\n        "Galop No": galop_no,\n        "At Adı": at_adi,\n        "Cinsiyet": cinsiyet,\n        "Yaş": yas,\n        "Pist Raw": pist,\n        "Galop Tipi": galop_tipi,\n        "Jokey": jokey,\n        "Mesafe Indexleri": " | ".join([f"{k}:{v}" for k, v in sorted(mesafe_indexleri.items())]),\n        "Mesafe Kaynak": mesafe_kaynak,\n        "Ham Galop": " | ".join(vals),\n    }\n\n\n# =========================\n# SCRAPER\n# =========================\n\ndef sayfadaki_program_tarihi(driver):\n    """Günlük yarış programı başlığındaki tarihi yakalar. Örn: 25/06/2026"""\n    try:\n        kaynak = driver.page_source or ""\n    except Exception:\n        kaynak = ""\n\n    m = re.search(r"(\\d{2}/\\d{2}/\\d{4})\\s+[^<\\n]*?-\\s*Yarış Programı", kaynak, re.IGNORECASE)\n    if m:\n        return m.group(1)\n\n    try:\n        body = driver.find_element(By.TAG_NAME, "body").text or ""\n    except Exception:\n        body = ""\n\n    m = re.search(r"(\\d{2}/\\d{2}/\\d{4})\\s+.*?-\\s*Yarış Programı", body, re.IGNORECASE)\n    if m:\n        return m.group(1)\n\n    m = re.search(r"\\b(\\d{2}/\\d{2}/\\d{4})\\b", body)\n    if m:\n        return m.group(1)\n\n    return ""\n\n\ndef yarin_programina_gec(driver):\n    """TJK günlük programında sağ ok/ileri gün ile yarının programına geçer.\n\n    Sadece Excel başlığını yarına almak tırt; gerçek program sayfası da yarına alınmalı.\n    Bu fonksiyon tarih değişmeden şehir linklerini toplamaya izin vermez.\n    """\n    hedef = beklenen_program_tarihi_token()\n    tarih_once = sayfadaki_program_tarihi(driver)\n    print(f"Program tarihi önce: {tarih_once if tarih_once else \'OKUNAMADI\'} | hedef yarın: {hedef}")\n\n    if tarih_once == hedef:\n        print("Program zaten hedef günde.")\n        return driver\n\n    ileri_tiklandi = False\n\n    # 1) Görünen ileri/next oku olan a/button elemanlarını dene.\n    elemanlar = []\n    try:\n        elemanlar.extend(driver.find_elements(By.TAG_NAME, "a"))\n    except Exception:\n        pass\n    try:\n        elemanlar.extend(driver.find_elements(By.TAG_NAME, "button"))\n    except Exception:\n        pass\n\n    for el in elemanlar:\n        try:\n            txt = (el.text or "").strip()\n            title = (el.get_attribute("title") or "").strip().lower()\n            aria = (el.get_attribute("aria-label") or "").strip().lower()\n            cls = (el.get_attribute("class") or "").strip().lower()\n            href = (el.get_attribute("href") or "").strip().lower()\n\n            ileri_mi = (\n                txt in [">", "›", "»", "Sonraki", "İleri"]\n                or "sonraki" in title or "ileri" in title or "next" in title\n                or "sonraki" in aria or "ileri" in aria or "next" in aria\n                or "next" in cls or "ileri" in cls or "sonraki" in cls\n                or "next" in href\n            )\n            if not ileri_mi:\n                continue\n\n            try:\n                el.click()\n            except Exception:\n                driver.execute_script("arguments[0].click();", el)\n            ileri_tiklandi = True\n            break\n        except StaleElementReferenceException:\n            continue\n        except Exception:\n            continue\n\n    # 2) Fallback: JS ile ileri butonu ara.\n    if not ileri_tiklandi:\n        try:\n            ileri_tiklandi = bool(driver.execute_script("""\n                const els = Array.from(document.querySelectorAll(\'a,button,span,div\'));\n                const e = els.find(x => {\n                    const t = (x.innerText || x.textContent || \'\').trim();\n                    const title = (x.getAttribute(\'title\') || \'\').toLowerCase();\n                    const aria = (x.getAttribute(\'aria-label\') || \'\').toLowerCase();\n                    const cls = (x.getAttribute(\'class\') || \'\').toLowerCase();\n                    return t === \'>\' || t === \'›\' || t === \'»\' ||\n                           title.includes(\'sonraki\') || title.includes(\'ileri\') || title.includes(\'next\') ||\n                           aria.includes(\'sonraki\') || aria.includes(\'ileri\') || aria.includes(\'next\') ||\n                           cls.includes(\'next\') || cls.includes(\'ileri\') || cls.includes(\'sonraki\');\n                });\n                if (e) { e.click(); return true; }\n                return false;\n            """))\n        except Exception:\n            ileri_tiklandi = False\n\n    if not ileri_tiklandi:\n        raise Exception("Yarın moduna geçilemedi: ileri gün oku bulunamadı.")\n\n    # Hedef tarih gelmeden devam yok.\n    for bekle_no in range(1, 31):\n        time.sleep(1)\n        tarih_sonra = sayfadaki_program_tarihi(driver)\n        if bekle_no in [3, 6, 10, 20, 30]:\n            print(f"Yarın bekleme {bekle_no}/30 | Tarih: {tarih_sonra if tarih_sonra else \'OKUNAMADI\'}")\n        if tarih_sonra == hedef:\n            print(f"Hedef güne geçildi: {tarih_once if tarih_once else \'OKUNAMADI\'} -> {tarih_sonra}")\n            return driver\n\n    raise Exception(f"İleri gün okuna basıldı ama hedef tarih gelmedi. Hedef={hedef}. Bugünün verisini çekmemek için durdu.")\n\n\ndef sehir_linklerini_bul():\n    driver = make_driver()\n    try:\n        ana_url = "https://www.tjk.org/TR/YarisSever/Info/Page/GunlukYarisProgrami"\n        safe_get(driver, ana_url)\n\n        # KRİTİK: Ana sayfa bugünü açar. Önce yarına geç, sonra şehir linklerini topla.\n        driver = yarin_programina_gec(driver)\n\n        links = driver.find_elements(By.TAG_NAME, "a")\n        sehir_linkleri = {}\n\n        for link in links:\n            try:\n                href = link.get_attribute("href")\n                text = link.text.strip()\n                if not href or "GunlukYarisProgrami?SehirId=" not in href:\n                    continue\n\n                for sehir in TURK_SEHIRLER:\n                    if sehir.lower() in text.lower() and sehir not in sehir_linkleri:\n                        # Era/tarih parametresini kırpma. Kırparsan yarın modu çöker.\n                        sehir_linkleri[sehir] = href\n            except StaleElementReferenceException:\n                continue\n\n        if not sehir_linkleri:\n            raise Exception("Yarın programında şehir linki bulunamadı.")\n\n        print("Yarın şehir linkleri toplandı:")\n        for s, u in sehir_linkleri.items():\n            print(f"- {s}: {u}")\n\n        return sehir_linkleri\n    finally:\n        driver.quit()\n\n\ndef kosu_linklerini_topla(driver, sehir_adi, program_url):\n    """\n    İdman linklerini daha sağlam toplar.\n\n    Eski sürüm sadece ekranda yakaladığı \'İdman Bilgileri\' elemanlarına sırayla tıklıyordu.\n    TJK sayfasında bazı şehirlerde/koşularda butonlar geç yüklenince veya DOM tıklamadan sonra\n    değişince bazı koşular, özellikle Kocaeli 4/6/8 gibi bloklar, hiç link listesine girmeyebiliyordu.\n\n    Yeni sürüm:\n    - Sayfadaki mevcut idmanpisti linklerini önce doğrudan toplar.\n    - Sayfayı aşağı/yukarı kaydırıp lazy yüklenen butonları da görünür yapar.\n    - \'İdman\' yazısını Türkçe karakter farkına takılmadan arar.\n    - Her tıklamadan sonra linkleri tekrar toplar.\n    - href yanında onclick/data-* alanlarında KosuKodu varsa onu da yakalar.\n    """\n    kosu_linkleri = {}\n\n    def norm_txt(s):\n        s = temizle(s)\n        s = s.replace("İ", "I").replace("ı", "i")\n        s = s.lower()\n        s = s.replace("i̇", "i")\n        return s\n\n    def link_ekle(href):\n        if not href:\n            return\n        if "/Info/idmanpisti/Kosu" not in href and "idmanpisti/Kosu" not in href:\n            return\n\n        if href.startswith("/"):\n            href2 = "https://www.tjk.org" + href\n        else:\n            href2 = href\n\n        parsed = urlparse(href2)\n        params = parse_qs(parsed.query)\n\n        if "KosuKodu" in params:\n            kosu_kodu = params["KosuKodu"][0]\n            kosu_linkleri.setdefault(kosu_kodu, href2)\n\n    def sayfadaki_linkleri_topla():\n        once = len(kosu_linkleri)\n\n        for link in driver.find_elements(By.TAG_NAME, "a"):\n            try:\n                link_ekle(link.get_attribute("href"))\n            except StaleElementReferenceException:\n                continue\n            except Exception:\n                continue\n\n        # Bazı TJK butonlarında link href yerine onclick/data alanında durabiliyor.\n        for el in driver.find_elements(By.XPATH, "//*[@onclick or @data-href or @data-url]"):\n            try:\n                attrs = [\n                    el.get_attribute("onclick"),\n                    el.get_attribute("data-href"),\n                    el.get_attribute("data-url"),\n                ]\n                for a in attrs:\n                    if not a:\n                        continue\n                    m = re.search(r"(?:KosuKodu=|KosuKodu%3D)(\\\\d+)", a, re.IGNORECASE)\n                    if m:\n                        kod = m.group(1)\n                        href = f"https://www.tjk.org/TR/YarisSever/Info/idmanpisti/Kosu?KosuKodu={kod}"\n                        link_ekle(href)\n            except StaleElementReferenceException:\n                continue\n            except Exception:\n                continue\n\n        return len(kosu_linkleri) - once\n\n    def idman_elemanlarini_bul():\n        adaylar = []\n\n        # Geniş arama: sadece exact \'İdman Bilgileri\' değil, Idman/idman/İDMAN varyasyonları.\n        elems = driver.find_elements(By.XPATH, "//*[contains(., \'dman\') or contains(., \'DMAN\') or contains(., \'İdman\') or contains(., \'idman\')]")\n\n        seen = set()\n        for el in elems:\n            try:\n                txt = norm_txt(el.text)\n                if "idman" not in txt:\n                    continue\n\n                tag = (el.tag_name or "").lower()\n                # Büyük container\'ları tıklamaya çalışma; mümkünse buton/link benzeri olanlar.\n                cls = norm_txt(el.get_attribute("class"))\n                role = norm_txt(el.get_attribute("role"))\n                href = el.get_attribute("href")\n\n                if tag not in ("a", "button", "span", "div", "td") and href is None:\n                    continue\n\n                key = el.id\n                if key in seen:\n                    continue\n                seen.add(key)\n                adaylar.append(el)\n            except StaleElementReferenceException:\n                continue\n            except Exception:\n                continue\n\n        return adaylar\n\n    safe_get(driver, program_url)\n    time.sleep(1.0)\n\n    # İlk görünen linkleri al.\n    sayfadaki_linkleri_topla()\n\n    # Lazy/accordion yapılar için sayfayı hareket ettir.\n    try:\n        driver.execute_script("window.scrollTo(0, 0);")\n        time.sleep(0.3)\n        driver.execute_script("window.scrollTo(0, document.body.scrollHeight);")\n        time.sleep(0.8)\n        driver.execute_script("window.scrollTo(0, 0);")\n        time.sleep(0.5)\n    except Exception:\n        pass\n\n    sayfadaki_linkleri_topla()\n\n    try:\n        WebDriverWait(driver, 12).until(lambda d: len(idman_elemanlarini_bul()) > 0 or len(kosu_linkleri) > 0)\n    except TimeoutException:\n        print(f"UYARI: {sehir_adi} idman butonu/linki bulunamadı.")\n\n    # DOM tıklama ile değişebildiği için birkaç tur gez.\n    tiklanan = set()\n\n    for tur in range(3):\n        buttons = idman_elemanlarini_bul()\n        if not buttons:\n            break\n\n        yeni_tiklama = 0\n\n        for idx in range(len(buttons)):\n            try:\n                buttons = idman_elemanlarini_bul()\n                if idx >= len(buttons):\n                    break\n\n                btn = buttons[idx]\n                key = btn.id\n\n                if key in tiklanan:\n                    continue\n\n                tiklanan.add(key)\n                yeni_tiklama += 1\n\n                driver.execute_script("arguments[0].scrollIntoView({block: \'center\'});", btn)\n                time.sleep(0.25)\n                driver.execute_script("arguments[0].click();", btn)\n                time.sleep(1.1)\n\n                sayfadaki_linkleri_topla()\n\n            except StaleElementReferenceException:\n                continue\n            except Exception as e:\n                print(f"{sehir_adi} İDMAN TIKLAMA HATASI [{idx + 1}]: {e}")\n                continue\n\n        sayfadaki_linkleri_topla()\n\n        if yeni_tiklama == 0:\n            break\n\n    if not kosu_linkleri:\n        print(f"UYARI: {sehir_adi} için hiç idman linki alınamadı.")\n    else:\n        print(f"{sehir_adi} idman link kodları: {\', \'.join(sorted(kosu_linkleri.keys()))}")\n\n    return kosu_linkleri\n\ndef kosudaki_atlari_cek(driver):\n    wait_table(driver)\n    tables = driver.find_elements(By.TAG_NAME, "table")\n    if not tables:\n        return []\n\n    rows = tables[0].find_elements(By.TAG_NAME, "tr")\n    horses = []\n    seen = set()\n\n    for row in rows[1:]:\n        cells = row.find_elements(By.TAG_NAME, "td")\n        if len(cells) < 2:\n            continue\n\n        at_no = cells[0].text.strip()\n        horse_name = cells[1].text.strip()\n        key = (at_no, horse_name.upper())\n\n        if horse_name and key not in seen:\n            horses.append({"at_no": at_no, "horse_name": horse_name})\n            seen.add(key)\n\n    return horses\n\n\ndef galoplari_at_icin_cek(driver, sehir_adi, kosu_adi, kosu_kodu, horse_name, at_no):\n    encoded_name = urllib.parse.quote(horse_name)\n    horse_url = (\n        "https://www.tjk.org/TR/YarisSever/Query/Page/"\n        f"IdmanIstatistikleri?1=1&QueryParameter_ATADI={encoded_name}"\n    )\n\n    last_error = None\n\n    for attempt in range(1, AT_RETRY + 1):\n        try:\n            safe_get(driver, horse_url)\n            wait_table(driver)\n            time.sleep(0.4)\n\n            tables = driver.find_elements(By.TAG_NAME, "table")\n            if not tables:\n                raise RuntimeError("tablo yok")\n\n            table = tables[0]\n            headers = tablo_headerlarini_al(table)\n            mesafe_indexleri = header_mesafe_indexleri(headers)\n            if not mesafe_indexleri:\n                print(f"  UYARI | {horse_name}: TJK mesafe başlığı okunamadı; mesafe tahmini yapılmayacak.")\n\n            galop_rows = table.find_elements(By.TAG_NAME, "tr")\n            kayitlar = []\n            eklenen = 0\n            page_text = driver.find_element(By.TAG_NAME, "body").text.upper()\n\n            # Sayfa at adını hiç içermiyorsa yarım/yanlış yükleme olabilir.\n            if horse_name.upper() not in page_text:\n                raise RuntimeError("sayfada at adı görünmedi")\n\n            for row in galop_rows[1:]:\n                if eklenen >= SON_GALOP_LIMIT:\n                    break\n\n                cells = row.find_elements(By.TAG_NAME, "td")\n                # Boş hücreleri SİLME. Silersen kolon indexi kayar ve 600/400 galobu 1400/1200 gibi yazılır.\n                values = [cell.text.strip() for cell in cells]\n                non_empty_values = [v for v in values if v.strip()]\n                if not non_empty_values:\n                    continue\n\n                # TJK aramada benzer isim döndürebilir; tam eşleşme şart.\n                if non_empty_values[0].strip().upper() != horse_name.upper():\n                    continue\n\n                kayit = galop_satiri_coz(\n                    values=values,\n                    sehir_adi=sehir_adi,\n                    kosu_adi=kosu_adi,\n                    kosu_kodu=kosu_kodu,\n                    horse_name=horse_name,\n                    at_no=at_no,\n                    galop_no=eklenen + 1,\n                    mesafe_indexleri=mesafe_indexleri,\n                )\n                kayitlar.append(kayit)\n                eklenen += 1\n\n            # Hiç galop yoksa bu bazen gerçek durum, bazen site gecikmesi.\n            # İlk iki denemede tekrar dene, son denemede boş kabul et.\n            if kayitlar or attempt == AT_RETRY:\n                return kayitlar\n\n            raise RuntimeError("0 galop geldi, retry")\n\n        except Exception as e:\n            last_error = e\n            if is_driver_dead_error(e):\n                raise DriverDiedError(f"{horse_name}: {e}")\n            print(f"  RETRY {attempt}/{AT_RETRY} | {horse_name}: {e}")\n            time.sleep(1.2 * attempt)\n\n    print(f"  AT BAŞARISIZ | {horse_name}: {last_error}")\n    return []\n\n\ndef sehir_isle(sehir_adi, program_url):\n    driver = make_driver()\n    rows_out = []\n    restart_count = 0\n    horse_counter = 0\n\n    try:\n        print()\n        print(f"========== {sehir_adi} BAŞLADI ==========")\n\n        while True:\n            try:\n                kosu_linkleri = kosu_linklerini_topla(driver, sehir_adi, program_url)\n                break\n            except Exception as e:\n                if is_driver_dead_error(e) and restart_count < MAX_DRIVER_RESTARTS_PER_CITY:\n                    restart_count += 1\n                    driver = restart_driver(driver, f"{sehir_adi} koşu linkleri alınırken session düştü")\n                    continue\n                raise\n\n        print(f"{sehir_adi} benzersiz koşu: {len(kosu_linkleri)}")\n\n        for sira_no, (kosu_kodu, kosu_link) in enumerate(sorted(kosu_linkleri.items()), 1):\n            attempt = 1\n            while attempt <= KOSU_RETRY:\n                try:\n                    safe_get(driver, kosu_link)\n                    horses = kosudaki_atlari_cek(driver)\n                    gercek_kosu_no = gercek_kosu_no_bul(driver, sira_no)\n                    kosu_adi = bugun_baslik_tarihi().format(sehir=sehir_adi, kosu_no=gercek_kosu_no)\n\n                    print()\n                    print(f"{kosu_adi}")\n                    print(f"{sehir_adi} {gercek_kosu_no}. koşu at sayısı: {len(horses)}")\n\n                    if not horses and attempt < KOSU_RETRY:\n                        raise RuntimeError("at listesi boş")\n\n                    for idx, horse in enumerate(horses, 1):\n                        at_no = horse["at_no"]\n                        horse_name = horse["horse_name"]\n\n                        horse_counter += 1\n                        if DRIVER_REFRESH_EVERY_HORSES and horse_counter > 1 and horse_counter % DRIVER_REFRESH_EVERY_HORSES == 0:\n                            driver = restart_driver(driver, f"koruyucu yenileme ({horse_counter} at)")\n\n                        print(f"  [{idx}/{len(horses)}] {at_no} - {horse_name}")\n\n                        horse_driver_retries = 0\n                        while True:\n                            try:\n                                kayitlar = galoplari_at_icin_cek(\n                                    driver=driver,\n                                    sehir_adi=sehir_adi,\n                                    kosu_adi=kosu_adi,\n                                    kosu_kodu=kosu_kodu,\n                                    horse_name=horse_name,\n                                    at_no=at_no,\n                                )\n                                rows_out.extend(kayitlar)\n                                print(f"      galop: {len(kayitlar)}")\n                                break\n\n                            except DriverDiedError:\n                                horse_driver_retries += 1\n                                restart_count += 1\n                                if restart_count > MAX_DRIVER_RESTARTS_PER_CITY or horse_driver_retries > 3:\n                                    print(f"      AT ATLADI | driver sürekli düşüyor: {horse_name}")\n                                    break\n                                driver = restart_driver(driver, f"{horse_name} sırasında session düştü")\n                                time.sleep(1.0)\n\n                        time.sleep(0.35)\n\n                    break\n\n                except Exception as e:\n                    if is_driver_dead_error(e):\n                        restart_count += 1\n                        if restart_count > MAX_DRIVER_RESTARTS_PER_CITY:\n                            print(f"{sehir_adi} DRIVER ÇOK DÜŞTÜ, şehir geçiliyor: {e}")\n                            break\n                        driver = restart_driver(driver, f"{sehir_adi} koşu sırasında session düştü")\n                        continue\n\n                    print(f"{sehir_adi} KOŞU RETRY {attempt}/{KOSU_RETRY}: {e}")\n                    time.sleep(1.5 * attempt)\n                    attempt += 1\n\n        print(f"========== {sehir_adi} BİTTİ | satır: {len(rows_out)} ==========")\n        return rows_out\n\n    finally:\n        try:\n            driver.quit()\n        except Exception:\n            pass\n\n\n# =========================\n# EXCEL\n# =========================\n\ndef excel_yaz(df):\n    kolon_sirasi = [\n        "Koşu", "At No", "Irk", "Tarih", "Şehir",\n        "400", "400 sn", "600", "600 sn", "800", "800 sn",\n        "1000", "1000 sn", "1200", "1200 sn", "1400", "1400 sn",\n        "Şekli", "Zemin", "Pist Türü", "Pist Durum",\n        "KosuKodu", "At", "Galop No", "At Adı", "Cinsiyet", "Yaş",\n        "Pist Raw", "Galop Tipi", "Jokey", "Mesafe Indexleri", "Mesafe Kaynak", "Ham Galop",\n    ]\n    df = df.reindex(columns=kolon_sirasi)\n\n    excel_path = Path(EXCEL_NAME)\n    if excel_path.exists():\n        with pd.ExcelWriter(EXCEL_NAME, engine="openpyxl", mode="a", if_sheet_exists="replace") as writer:\n            df.to_excel(writer, sheet_name=HAM_SHEET, index=False)\n    else:\n        with pd.ExcelWriter(EXCEL_NAME, engine="openpyxl", mode="w") as writer:\n            df.to_excel(writer, sheet_name=HAM_SHEET, index=False)\n\n    return len(df)\n\n\n# =========================\n# MAIN\n# =========================\n\ndef main():\n    print("Şehir linkleri toplanıyor...")\n    sehir_linkleri = sehir_linklerini_bul()\n\n    print("\\nBULUNAN ŞEHİRLER:")\n    for sehir in sehir_linkleri:\n        print("-", sehir)\n\n    if TEST_MODU:\n        sehir_linkleri = dict(list(sehir_linkleri.items())[:1])\n\n    all_rows = []\n    print("\\nSIRALI çalışma başlıyor. Worker yok. Veri güvenliği öncelik.")\n\n    for idx, (sehir, url) in enumerate(sehir_linkleri.items(), 1):\n        print(f"\\n### ŞEHİR {idx}/{len(sehir_linkleri)}: {sehir}")\n        try:\n            rows = sehir_isle(sehir, url)\n            all_rows.extend(rows)\n            print(f"{sehir} eklendi. Toplam satır: {len(all_rows)}")\n        except WebDriverException as e:\n            print(f"{sehir} DRIVER HATASI: {e}")\n        except Exception as e:\n            print(f"{sehir} GENEL HATA: {e}")\n\n        time.sleep(CITY_SLEEP)\n\n    df = pd.DataFrame(all_rows)\n    total = excel_yaz(df)\n\n    print("\\n========== TAMAMLANDI ==========")\n    print("Excel:", EXCEL_NAME)\n    print("Güncellenen sayfa:", HAM_SHEET)\n    print("Korunan sayfalar: medyan / yapılacak yer / xy / xx varsa silinmedi")\n    print("Toplam satır:", total)\n    print("Not: Bu sürüm paralel çalışmaz; at atlamamak için şehirleri ve atları sırayla işler.")\n\n    input("\\nKapatmak için Enter bas...")\n\n\nif __name__ == "__main__":\n    main()\n'

YAPILACAK_YER_CODE = 'import re\nfrom pathlib import Path\n\nimport pandas as pd\nfrom openpyxl import load_workbook\nfrom openpyxl.styles import Font, PatternFill, Alignment\nfrom openpyxl.utils import get_column_letter\n\n\n# =========================\n# AYARLAR\n# =========================\n\nINPUT_EXCEL = "tjk_ULTRA_MESAFELI.xlsx"\nHAM_SHEET = "ham veri"\nMEDYAN_SHEET = "medyan"\nOUT_SHEET = "yapılacak yer"\n\nTURK_SEHIRLER = [\n    "Şanlıurfa", "Diyarbakır", "Elazığ", "Adana", "Ankara",\n    "Antalya", "İzmir", "Bursa", "Kocaeli", "İstanbul"\n]\n\nMESAFELER = [400, 600, 800, 1000, 1200, 1400]\n\nOUT_HEADERS = [\n    "koşu no",\n    "at no",\n    "ırk",\n    "tarih",\n    "şehir",\n\n    "400",\n    "400 farkı",\n\n    "600",\n    "600 farkı",\n    "600 ile 400 fark toplamı",\n\n    "800",\n    "800 farkı",\n    "800 ile 400 fark toplamı",\n\n    "1000",\n    "1000 farkı",\n    "1000 ile 400 fark toplamı",\n\n    "1200",\n    "1200 farkı",\n    "1200 ile 400 fark toplamı",\n\n    "1400",\n    "1400 farkı",\n    "1400 ile 400 fark toplamı",\n\n    "şekli",\n    "zemin",\n    "pist türü",\n    "pist durum",\n]\n\n\n# =========================\n# TEMEL FONKSİYONLAR\n# =========================\n\ndef temizle(x):\n    if pd.isna(x):\n        return ""\n    return str(x).strip()\n\n\ndef clean_key(s):\n    s = temizle(s)\n    s = s.replace("\\u00A0", "")\n    s = s.replace(" ", "")\n    s = s.replace("\\t", "")\n    return s.strip()\n\n\ndef to_num(x):\n    if pd.isna(x):\n        return None\n\n    if isinstance(x, (int, float)):\n        return float(x)\n\n    s = temizle(x)\n    if s == "":\n        return None\n\n    s = s.replace(",", ".")\n\n    try:\n        return float(s)\n    except:\n        return None\n\n\ndef sum_if_both_numeric(f400, fx):\n    if fx is None or fx == "":\n        return ""\n    if f400 is None or f400 == "":\n        return ""\n\n    try:\n        return float(f400) + float(fx)\n    except:\n        return ""\n\n\ndef get_top_mesafe_from_row(row):\n    for m in [1400, 1200, 1000, 800, 600, 400]:\n        val = to_num(row.get(f"{m} sn", None))\n        if val is not None:\n            return m\n    return 0\n\n\n# =========================\n# PİST / ŞEHİR PARSER\n# =========================\n\ndef normalize_pist(galop_sehir, pist_raw):\n    """\n    FINAL KURAL:\n\n    İstanbul / Antalya:\n        Sentetik -> zemin Kum, pist türü Normal\n        Kum / İç / İç Kum -> zemin Kum, pist türü İç\n\n    Diğer şehirler:\n        İç / İç Kum / Kum-İç -> zemin Kum, pist türü İç\n        Kum -> zemin Kum, pist türü Normal\n        Çim -> zemin Çim, pist türü Normal\n\n    \'İç\' asla zemin olarak yazılmaz.\n    """\n    sehir = temizle(galop_sehir)\n    pist = temizle(pist_raw)\n\n    t = pist.lower()\n    t_norm = t.replace("ı", "i")\n\n    pist_durum = "Nemli" if "nemli" in t_norm else ""\n\n    has_ic = ("iç" in t) or ("ic" in t_norm)\n    has_kum = "kum" in t_norm\n    has_sentetik = "sentetik" in t_norm\n    has_cim = ("çim" in t) or ("cim" in t_norm)\n\n    # İstanbul / Antalya özel kuralın\n    if sehir in ["İstanbul", "Antalya"]:\n        if has_sentetik:\n            return "Kum", "Normal", pist_durum\n\n        if has_kum or has_ic:\n            return "Kum", "İç", pist_durum\n\n    # Diğer şehirler\n    if has_ic:\n        return "Kum", "İç", pist_durum\n\n    if has_kum or has_sentetik:\n        return "Kum", "Normal", pist_durum\n\n    if has_cim:\n        return "Çim", "Normal", pist_durum\n\n    if pist == "":\n        return "", "Normal", pist_durum\n\n    # Buraya düşerse bile İç\'i zemin yapma\n    if pist.lower() in ["iç", "ic"]:\n        return "Kum", "İç", pist_durum\n\n    return pist, "Normal", pist_durum\n\ndef parse_ham_galop_city_pist(row):\n    """\n    Ham Galop içinden gerçek galop şehrini ve pist bilgisini bulur.\n\n    Bu sürüm daha sert:\n    - Şehirden sonra \'İç\' geçiyorsa pist_raw = Kum-İç\n    - Şehirden sonra \'Sentetik\' geçiyorsa pist_raw = Sentetik\n    - Şehirden sonra \'Kum\' geçiyorsa pist_raw = Kum\n    - İç asla tek başına zemin olarak bırakılmaz.\n    """\n    ham = temizle(row.get("Ham Galop", ""))\n    fallback_sehir = temizle(row.get("Şehir", ""))\n    fallback_pist = temizle(row.get("Pist Raw", ""))\n\n    if not ham:\n        return fallback_sehir, fallback_pist\n\n    parts = [temizle(p) for p in ham.split("|")]\n    parts = [p for p in parts if p]\n\n    tarih_idx = -1\n    for i, p in enumerate(parts):\n        if re.fullmatch(r"\\d{1,2}[./]\\d{1,2}[./]\\d{4}", p):\n            tarih_idx = i\n            break\n\n    if tarih_idx == -1:\n        return fallback_sehir, fallback_pist\n\n    galop_sehir = fallback_sehir\n    sehir_idx = -1\n\n    for i in range(tarih_idx + 1, len(parts)):\n        for s in TURK_SEHIRLER:\n            if parts[i].lower() == s.lower():\n                galop_sehir = s\n                sehir_idx = i\n                break\n\n        if sehir_idx != -1:\n            break\n\n    if sehir_idx == -1:\n        return fallback_sehir, fallback_pist\n\n    # Şehirden sonra pist / galop tipi / jokey alanları gelir.\n    after_city = parts[sehir_idx + 1: sehir_idx + 6]\n\n    # Galop / Sprint / Detay gelene kadar olan parçaları pist bilgisi olarak değerlendir.\n    pist_tokens = []\n    for token in after_city:\n        tl = token.lower()\n        if tl in ["galop", "sprint", "detay"]:\n            break\n        pist_tokens.append(token)\n\n    joined = " ".join(pist_tokens)\n    j = joined.lower().replace("ı", "i")\n\n    if "sentetik" in j:\n        pist_raw = "Sentetik"\n    elif "iç" in joined.lower() or "ic" in j:\n        pist_raw = "Kum-İç"\n    elif "kum" in j:\n        pist_raw = "Kum"\n    elif "çim" in joined.lower() or "cim" in j:\n        pist_raw = "Çim"\n    else:\n        pist_raw = fallback_pist\n\n    return galop_sehir, pist_raw\n\n\n# =========================\n# MEDYAN\n# =========================\n\ndef build_median_lookup(df_med):\n    """\n    VBA\'daki GetMedian mantığı:\n    - key: medyan A sütunu\n    - 400 -> H\n    - 600 -> I\n    - 800 -> J\n    - 1000 -> K\n    - 1200 -> L\n    - 1400 -> M\n    """\n    lookup = {}\n\n    for _, r in df_med.iterrows():\n        key = clean_key(r.iloc[0])\n        if key == "":\n            continue\n\n        lookup[key] = {\n            400: to_num(r.iloc[7]) if len(r) > 7 else None,\n            600: to_num(r.iloc[8]) if len(r) > 8 else None,\n            800: to_num(r.iloc[9]) if len(r) > 9 else None,\n            1000: to_num(r.iloc[10]) if len(r) > 10 else None,\n            1200: to_num(r.iloc[11]) if len(r) > 11 else None,\n            1400: to_num(r.iloc[12]) if len(r) > 12 else None,\n        }\n\n    return lookup\n\n\ndef calc_diff(med_lookup, sehir, irk, pist_turu, top_mesafe, ara_mesafe, ham_val):\n    ham = to_num(ham_val)\n    if ham is None:\n        return ""\n\n    key = clean_key(sehir) + clean_key(irk) + clean_key(pist_turu) + str(top_mesafe) + "400"\n    key = clean_key(key)\n\n    med_row = med_lookup.get(key)\n    if not med_row:\n        return ""\n\n    med_val = med_row.get(ara_mesafe)\n    if med_val is None:\n        return ""\n\n    return ham - med_val\n\n\n# =========================\n# ANA İŞLEM\n# =========================\n\ndef main():\n    input_path = Path(INPUT_EXCEL)\n\n    if not input_path.exists():\n        raise FileNotFoundError(\n            f"{INPUT_EXCEL} bulunamadı. Python dosyasıyla Excel aynı klasörde olmalı."\n        )\n\n    print("Excel okunuyor:", INPUT_EXCEL)\n\n    xls = pd.ExcelFile(INPUT_EXCEL)\n    sheets = xls.sheet_names\n\n    if HAM_SHEET not in sheets:\n        raise ValueError(f"\'{HAM_SHEET}\' sayfası yok. İlk sayfanın adını \'ham veri\' yap.")\n\n    if MEDYAN_SHEET not in sheets:\n        raise ValueError(f"\'{MEDYAN_SHEET}\' sayfası yok. Medyan sayfasının adı \'medyan\' olmalı.")\n\n    df_ham = pd.read_excel(INPUT_EXCEL, sheet_name=HAM_SHEET)\n    df_med = pd.read_excel(INPUT_EXCEL, sheet_name=MEDYAN_SHEET)\n\n    med_lookup = build_median_lookup(df_med)\n\n    out_rows = []\n\n    for _, row in df_ham.iterrows():\n        kosu_no = temizle(row.get("Koşu", ""))\n\n        at_no = temizle(row.get("At No", ""))\n        if at_no == "":\n            at_no = temizle(row.get("At", ""))\n\n        irk = temizle(row.get("Irk", ""))\n        tarih = row.get("Tarih", "")\n        sekli = temizle(row.get("Şekli", ""))\n\n        galop_sehir, pist_raw = parse_ham_galop_city_pist(row)\n        zemin, pist_turu, pist_durum = normalize_pist(galop_sehir, pist_raw)\n\n        v400 = to_num(row.get("400 sn", None))\n        v600 = to_num(row.get("600 sn", None))\n        v800 = to_num(row.get("800 sn", None))\n        v1000 = to_num(row.get("1000 sn", None))\n        v1200 = to_num(row.get("1200 sn", None))\n        v1400 = to_num(row.get("1400 sn", None))\n\n        numeric_map = {\n            400: v400,\n            600: v600,\n            800: v800,\n            1000: v1000,\n            1200: v1200,\n            1400: v1400,\n        }\n\n        top_mesafe = 0\n        for m in [1400, 1200, 1000, 800, 600, 400]:\n            if numeric_map[m] is not None:\n                top_mesafe = m\n                break\n\n        is_kenter = ("kenter" in sekli.lower()) or top_mesafe == 0\n\n        if is_kenter:\n            f400 = f600 = f800 = f1000 = f1200 = f1400 = ""\n            sekli_out = "KENTER"\n        else:\n            f400 = calc_diff(med_lookup, galop_sehir, irk, pist_turu, top_mesafe, 400, v400)\n            f600 = calc_diff(med_lookup, galop_sehir, irk, pist_turu, top_mesafe, 600, v600)\n            f800 = calc_diff(med_lookup, galop_sehir, irk, pist_turu, top_mesafe, 800, v800)\n            f1000 = calc_diff(med_lookup, galop_sehir, irk, pist_turu, top_mesafe, 1000, v1000)\n            f1200 = calc_diff(med_lookup, galop_sehir, irk, pist_turu, top_mesafe, 1200, v1200)\n            f1400 = calc_diff(med_lookup, galop_sehir, irk, pist_turu, top_mesafe, 1400, v1400)\n            sekli_out = sekli\n\n        out_rows.append([\n            kosu_no,\n            at_no,\n            irk,\n            tarih,\n            galop_sehir,\n\n            v400 if v400 is not None else "",\n            f400,\n\n            v600 if v600 is not None else "",\n            f600,\n            sum_if_both_numeric(f400, f600),\n\n            v800 if v800 is not None else "",\n            f800,\n            sum_if_both_numeric(f400, f800),\n\n            v1000 if v1000 is not None else "",\n            f1000,\n            sum_if_both_numeric(f400, f1000),\n\n            v1200 if v1200 is not None else "",\n            f1200,\n            sum_if_both_numeric(f400, f1200),\n\n            v1400 if v1400 is not None else "",\n            f1400,\n            sum_if_both_numeric(f400, f1400),\n\n            sekli_out,\n            zemin,\n            pist_turu,\n            pist_durum,\n        ])\n\n    print("Yapılacak yer satır:", len(out_rows))\n\n    wb = load_workbook(INPUT_EXCEL)\n\n    if OUT_SHEET in wb.sheetnames:\n        del wb[OUT_SHEET]\n\n    ws = wb.create_sheet(OUT_SHEET)\n\n    ws.append(OUT_HEADERS)\n\n    for row in out_rows:\n        ws.append(row)\n\n    header_fill = PatternFill("solid", fgColor="D9EAF7")\n    header_font = Font(bold=True)\n\n    for cell in ws[1]:\n        cell.fill = header_fill\n        cell.font = header_font\n        cell.alignment = Alignment(horizontal="center", vertical="center")\n\n    ws.freeze_panes = "A2"\n\n    for row in ws.iter_rows(min_row=2):\n        for cell in row:\n            if isinstance(cell.value, float):\n                cell.number_format = "0.00"\n\n    for col in range(1, ws.max_column + 1):\n        letter = get_column_letter(col)\n        ws.column_dimensions[letter].width = 16\n\n    for letter in ["A", "B", "C", "E", "W", "X", "Y", "Z"]:\n        ws.column_dimensions[letter].width = 22\n\n    wb.save(INPUT_EXCEL)\n\n    print("Tamamlandı.")\n    print("Çıktı sayfası:", OUT_SHEET)\n    print("Dosya:", INPUT_EXCEL)\n    print("Kural: İç artık zemin değil; zemin Kum, pist türü İç.")\n\n    input("\\nKapatmak için Enter bas...")\n\n\nif __name__ == "__main__":\n    main()\n'

XY_XX_CODE = 'from __future__ import annotations\n\nimport sys\nfrom datetime import datetime, date, timedelta\nfrom pathlib import Path\nfrom typing import Any, Dict, List, Optional, Tuple\n\nfrom openpyxl import load_workbook\nfrom openpyxl.styles import Font, PatternFill, Alignment\nfrom openpyxl.utils import get_column_letter\n\nINPUT_EXCEL = "tjk_ULTRA_MESAFELI.xlsx"\nSOURCE_SHEET = "yapılacak yer"\nXY_SHEET = "xy"   # Eski makro: Sayfa2 / 36 gün özet\nXX_SHEET = "xx"   # Eski makro: Sayfa3 / son galop\n\n# yapılacak yer kolonları, 1-based Excel numaraları\nCOL_KOSU = 1\nCOL_ATNO = 2\nCOL_TARIH = 4\nCOL_SEHIR = 5\nCOL_400_FARK = 7\nCOL_600_400 = 10\nCOL_800_400 = 13\nCOL_1000_400 = 16\nCOL_1200_400 = 19\nCOL_1400_400 = 22\nCOL_SEKLI = 23\n\nBLOCKS_XY = [\n    (COL_1400_400, 1, "1400+400", False),\n    (COL_1200_400, 7, "1200+400", False),\n    (COL_1000_400, 13, "1000+400", False),\n    (COL_800_400, 19, "800+400", False),\n    (COL_600_400, 25, "600+400", False),\n    (COL_400_FARK, 31, "400 farkı", True),\n]\n\nBLOCKS_XX = [\n    (COL_1400_400, 1, "1400+400"),\n    (COL_1200_400, 8, "1200+400"),\n    (COL_1000_400, 15, "1000+400"),\n    (COL_800_400, 22, "800+400"),\n    (COL_600_400, 29, "600+400"),\n    (COL_400_FARK, 36, "400 farkı"),\n]\n\nHEADER_FILL = PatternFill("solid", fgColor="D9EAF7")\nYELLOW_FILL = PatternFill("solid", fgColor="FFF200")\nBOLD = Font(bold=True)\nRACE_FONT = Font(bold=True, size=12)\nCENTER = Alignment(horizontal="center", vertical="center")\n\n\ndef clean(x: Any) -> str:\n    if x is None:\n        return ""\n    return str(x).strip()\n\n\ndef parse_date(x: Any) -> Optional[date]:\n    if x is None or x == "":\n        return None\n    if isinstance(x, datetime):\n        return x.date()\n    if isinstance(x, date):\n        return x\n    s = clean(x)\n    for fmt in ("%d.%m.%Y", "%d/%m/%Y", "%Y-%m-%d", "%d-%m-%Y"):\n        try:\n            return datetime.strptime(s, fmt).date()\n        except ValueError:\n            pass\n    return None\n\n\ndef try_num(x: Any) -> Optional[float]:\n    if x is None or x == "":\n        return None\n    if isinstance(x, bool):\n        return None\n    if isinstance(x, (int, float)):\n        return float(x)\n    s = clean(x).replace("\\u00A0", "").replace(" ", "")\n    if not s:\n        return None\n    s = s.replace(",", ".")\n    try:\n        return float(s)\n    except ValueError:\n        return None\n\n\ndef reset_sheet(wb, name: str):\n    if name in wb.sheetnames:\n        del wb[name]\n    return wb.create_sheet(name)\n\n\ndef max_date_in_sheet(ws) -> Optional[date]:\n    max_d = None\n    for r in range(2, ws.max_row + 1):\n        d = parse_date(ws.cell(r, COL_TARIH).value)\n        if d and (max_d is None or d > max_d):\n            max_d = d\n    return max_d\n\n\ndef unique_races(ws, min_d: Optional[date] = None, max_d: Optional[date] = None) -> List[str]:\n    seen = set()\n    out = []\n    for r in range(2, ws.max_row + 1):\n        race = clean(ws.cell(r, COL_KOSU).value)\n        if not race or race in seen:\n            continue\n        d = parse_date(ws.cell(r, COL_TARIH).value)\n        if min_d is not None or max_d is not None:\n            if not d:\n                continue\n            if min_d and d < min_d:\n                continue\n            if max_d and d > max_d:\n                continue\n        seen.add(race)\n        out.append(race)\n    return out\n\n\ndef write_xy_block_headers(ws, top_row: int, out_col: int, title: str):\n    ws.cell(top_row, out_col).value = title\n    headers = ["at no", "değer", "şekli", "tarih", "koşu no"]\n    for i, h in enumerate(headers):\n        ws.cell(top_row + 1, out_col + i).value = h\n    for row in ws.iter_rows(min_row=top_row, max_row=top_row + 1, min_col=out_col, max_col=out_col + 4):\n        for c in row:\n            c.font = BOLD\n            c.fill = HEADER_FILL\n            c.alignment = CENTER\n    for rr in range(top_row + 1, top_row + 13):\n        ws.cell(rr, out_col + 4).fill = YELLOW_FILL\n\n\ndef write_xy_kenter_headers(ws, top_row: int, out_col: int):\n    ws.cell(top_row, out_col).value = "KENTER (son 5 gün)"\n    ws.cell(top_row + 1, out_col).value = "at no"\n    ws.cell(top_row + 1, out_col + 1).value = "tarih"\n    for row in ws.iter_rows(min_row=top_row, max_row=top_row + 1, min_col=out_col, max_col=out_col + 1):\n        for c in row:\n            c.font = BOLD\n            c.fill = HEADER_FILL\n            c.alignment = CENTER\n\n\ndef fill_xy_block(ws_src, ws_out, race: str, min_d: date, max_d: date, used_rows: set[int], source_col: int, out_col: int, top_row: int, only_minus_one_or_less: bool):\n    cand: List[Tuple[float, int]] = []\n    for r in range(2, ws_src.max_row + 1):\n        if r in used_rows:\n            continue\n        if clean(ws_src.cell(r, COL_KOSU).value) != race:\n            continue\n        d = parse_date(ws_src.cell(r, COL_TARIH).value)\n        if not d or d < min_d or d > max_d:\n            continue\n        v = try_num(ws_src.cell(r, source_col).value)\n        if v is None:\n            continue\n        if only_minus_one_or_less:\n            if v <= -1:\n                cand.append((v, r))\n        else:\n            if v < 0:\n                cand.append((v, r))\n\n    cand.sort(key=lambda x: x[0])\n    for i, (v, rr) in enumerate(cand[:10], start=1):\n        wr = top_row + 1 + i\n        ws_out.cell(wr, out_col).value = ws_src.cell(rr, COL_ATNO).value\n        ws_out.cell(wr, out_col + 1).value = v\n        ws_out.cell(wr, out_col + 2).value = ws_src.cell(rr, COL_SEKLI).value\n        ws_out.cell(wr, out_col + 3).value = ws_src.cell(rr, COL_TARIH).value\n        ws_out.cell(wr, out_col + 4).value = ws_src.cell(rr, COL_KOSU).value\n        used_rows.add(rr)\n\n\ndef fill_xy_kenters(ws_src, ws_out, race: str, max_d: date, out_col: int, top_row: int):\n    min_d = max_d - timedelta(days=4)\n    wr = top_row + 2\n    for r in range(2, ws_src.max_row + 1):\n        if clean(ws_src.cell(r, COL_KOSU).value) != race:\n            continue\n        d = parse_date(ws_src.cell(r, COL_TARIH).value)\n        if not d or d < min_d or d > max_d:\n            continue\n        if "KENTER" in clean(ws_src.cell(r, COL_SEKLI).value).upper():\n            ws_out.cell(wr, out_col).value = ws_src.cell(r, COL_ATNO).value\n            ws_out.cell(wr, out_col + 1).value = ws_src.cell(r, COL_TARIH).value\n            wr += 1\n\n\ndef build_xy(ws_src, ws_out):\n    max_d = max_date_in_sheet(ws_src)\n    if not max_d:\n        raise ValueError("yapılacak yer sayfasında tarih bulunamadı.")\n    min_d = max_d - timedelta(days=36)\n    races = unique_races(ws_src, min_d, max_d)\n    if not races:\n        raise ValueError("Son 36 gün içinde koşu bulunamadı.")\n\n    out_row = 1\n    for race in races:\n        ws_out.cell(out_row, 1).value = race\n        ws_out.cell(out_row, 1).font = RACE_FONT\n        top_row = out_row + 1\n        used_rows: set[int] = set()\n        for source_col, out_col, title, only_minus in BLOCKS_XY:\n            write_xy_block_headers(ws_out, top_row, out_col, title)\n            fill_xy_block(ws_src, ws_out, race, min_d, max_d, used_rows, source_col, out_col, top_row, only_minus)\n        write_xy_kenter_headers(ws_out, top_row, 37)\n        fill_xy_kenters(ws_src, ws_out, race, max_d, 37, top_row)\n        out_row += 15\n\n\ndef latest_rows_by_horse(ws_src, race: str) -> List[int]:\n    latest: Dict[str, int] = {}\n    for r in range(2, ws_src.max_row + 1):\n        if clean(ws_src.cell(r, COL_KOSU).value) != race:\n            continue\n        horse = clean(ws_src.cell(r, COL_ATNO).value)\n        d = parse_date(ws_src.cell(r, COL_TARIH).value)\n        if not horse or not d:\n            continue\n        old = latest.get(horse)\n        if old is None:\n            latest[horse] = r\n            continue\n        old_d = parse_date(ws_src.cell(old, COL_TARIH).value)\n        if old_d is None or d > old_d or (d == old_d and r > old):\n            latest[horse] = r\n    return list(latest.values())\n\n\ndef write_xx_block_headers(ws, top_row: int, out_col: int, title: str):\n    ws.cell(top_row, out_col).value = title\n    headers = ["at no", "değer", "şekli", "tarih", "şehir", "koşu no"]\n    for i, h in enumerate(headers):\n        ws.cell(top_row + 1, out_col + i).value = h\n    for row in ws.iter_rows(min_row=top_row, max_row=top_row + 1, min_col=out_col, max_col=out_col + 5):\n        for c in row:\n            c.font = BOLD\n            c.fill = HEADER_FILL\n            c.alignment = CENTER\n\n\ndef write_xx_kenter_headers(ws, top_row: int, out_col: int):\n    ws.cell(top_row, out_col).value = "KENTER (son galop)"\n    headers = ["at no", "şekli", "tarih", "şehir", "koşu no"]\n    for i, h in enumerate(headers):\n        ws.cell(top_row + 1, out_col + i).value = h\n    for row in ws.iter_rows(min_row=top_row, max_row=top_row + 1, min_col=out_col, max_col=out_col + 4):\n        for c in row:\n            c.font = BOLD\n            c.fill = HEADER_FILL\n            c.alignment = CENTER\n\n\ndef fill_xx_block(ws_src, ws_out, latest_rows: List[int], used_latest: set[int], source_col: int, out_col: int, top_row: int):\n    cand: List[Tuple[float, int, int]] = []\n    for idx, rr in enumerate(latest_rows):\n        if idx in used_latest:\n            continue\n        v = try_num(ws_src.cell(rr, source_col).value)\n        if v is None:\n            continue\n        cand.append((v, rr, idx))\n    cand.sort(key=lambda x: x[0])\n    for i, (v, rr, idx) in enumerate(cand, start=1):\n        wr = top_row + 1 + i\n        ws_out.cell(wr, out_col).value = ws_src.cell(rr, COL_ATNO).value\n        ws_out.cell(wr, out_col + 1).value = v\n        ws_out.cell(wr, out_col + 2).value = ws_src.cell(rr, COL_SEKLI).value\n        ws_out.cell(wr, out_col + 3).value = ws_src.cell(rr, COL_TARIH).value\n        ws_out.cell(wr, out_col + 4).value = ws_src.cell(rr, COL_SEHIR).value\n        ws_out.cell(wr, out_col + 5).value = ws_src.cell(rr, COL_KOSU).value\n        used_latest.add(idx)\n\n\ndef fill_xx_kenters(ws_src, ws_out, latest_rows: List[int], out_col: int, top_row: int):\n    wr = top_row + 2\n    for rr in latest_rows:\n        if "KENTER" in clean(ws_src.cell(rr, COL_SEKLI).value).upper():\n            ws_out.cell(wr, out_col).value = ws_src.cell(rr, COL_ATNO).value\n            ws_out.cell(wr, out_col + 1).value = ws_src.cell(rr, COL_SEKLI).value\n            ws_out.cell(wr, out_col + 2).value = ws_src.cell(rr, COL_TARIH).value\n            ws_out.cell(wr, out_col + 3).value = ws_src.cell(rr, COL_SEHIR).value\n            ws_out.cell(wr, out_col + 4).value = ws_src.cell(rr, COL_KOSU).value\n            wr += 1\n\n\ndef last_used_row(ws, min_row: int, max_col: int = 47) -> int:\n    last = min_row + 1\n    for col in range(1, max_col + 1):\n        for row in range(ws.max_row, min_row - 1, -1):\n            if ws.cell(row, col).value not in (None, ""):\n                if row > last:\n                    last = row\n                break\n    return last\n\n\ndef build_xx(ws_src, ws_out):\n    races = unique_races(ws_src)\n    if not races:\n        raise ValueError("Koşu bulunamadı.")\n    out_row = 1\n    for race in races:\n        ws_out.cell(out_row, 1).value = race\n        ws_out.cell(out_row, 1).font = RACE_FONT\n        top_row = out_row + 1\n        latest_rows = latest_rows_by_horse(ws_src, race)\n        used_latest: set[int] = set()\n        for source_col, out_col, title in BLOCKS_XX:\n            write_xx_block_headers(ws_out, top_row, out_col, title)\n            fill_xx_block(ws_src, ws_out, latest_rows, used_latest, source_col, out_col, top_row)\n        write_xx_kenter_headers(ws_out, top_row, 43)\n        fill_xx_kenters(ws_src, ws_out, latest_rows, 43, top_row)\n        out_row = last_used_row(ws_out, top_row, 47) + 3\n\n\ndef format_sheet(ws):\n    ws.freeze_panes = "A1"\n    for row in ws.iter_rows():\n        for cell in row:\n            if isinstance(cell.value, float):\n                cell.number_format = "0.00"\n            if isinstance(cell.value, (datetime, date)):\n                cell.number_format = "dd.mm.yyyy"\n            cell.alignment = Alignment(vertical="center")\n    for col in range(1, ws.max_column + 1):\n        letter = get_column_letter(col)\n        max_len = 8\n        for cell in ws[letter]:\n            val = cell.value\n            if val is not None:\n                max_len = max(max_len, len(str(val)))\n        ws.column_dimensions[letter].width = min(max_len + 2, 22)\n\n\ndef main(path: str = INPUT_EXCEL):\n    input_path = Path(path)\n    if not input_path.exists():\n        raise FileNotFoundError(f"Dosya bulunamadı: {input_path}")\n\n    keep_vba = input_path.suffix.lower() == ".xlsm"\n    wb = load_workbook(input_path, keep_vba=keep_vba)\n    if SOURCE_SHEET not in wb.sheetnames:\n        raise ValueError(f"\'{SOURCE_SHEET}\' sayfası yok. Önce yapılacak yer sayfası üretilmeli.")\n\n    ws_src = wb[SOURCE_SHEET]\n    ws_xy = reset_sheet(wb, XY_SHEET)\n    ws_xx = reset_sheet(wb, XX_SHEET)\n\n    build_xy(ws_src, ws_xy)\n    build_xx(ws_src, ws_xx)\n\n    format_sheet(ws_xy)\n    format_sheet(ws_xx)\n\n    wb.save(input_path)\n    print("Tamamlandı.")\n    print("Kaynak sayfa:", SOURCE_SHEET)\n    print("Oluşan sayfalar:", XY_SHEET, XX_SHEET)\n    print("Dosya:", input_path)\n\n\nif __name__ == "__main__":\n    main(sys.argv[1] if len(sys.argv) > 1 else INPUT_EXCEL)\n'


def _load_module_from_code(code: str, name: str) -> dict:
    ns = {"__name__": name, "__file__": f"{name}.py"}
    exec(compile(code, f"{name}.py", "exec"), ns)
    return ns


def _call_without_input(func, *args, **kwargs):
    old_input = builtins.input
    builtins.input = lambda *a, **k: ""
    try:
        return func(*args, **kwargs)
    finally:
        builtins.input = old_input


def _medyan_enjekte(excel_name):
    """Taze galop dosyasına statik 'medyan' referans sayfasını ekler.
    Kaynak öncelik: galop_medyan.xlsx -> tjk_ULTRA_MESAFELI.xlsx."""
    import openpyxl, os
    wb = openpyxl.load_workbook(excel_name)
    if "medyan" in wb.sheetnames:
        print("medyan zaten var, atlanıyor.")
        wb.close()
        return
    kaynak = next((a for a in ["galop_medyan.xlsx", "tjk_ULTRA_MESAFELI.xlsx"]
                   if os.path.exists(a)), None)
    if not kaynak:
        print("UYARI: medyan referansı yok (galop_medyan.xlsx / tjk_ULTRA_MESAFELI.xlsx).")
        wb.close()
        return
    wb_ref = openpyxl.load_workbook(kaynak, data_only=False)
    if "medyan" not in wb_ref.sheetnames:
        print(f"UYARI: {kaynak} içinde 'medyan' sayfası yok.")
        wb.close(); wb_ref.close()
        return
    src = wb_ref["medyan"]
    dst = wb.create_sheet("medyan")
    for row in src.iter_rows():
        for c in row:
            dst.cell(c.row, c.column, c.value)
    wb.save(excel_name)
    wb_ref.close()
    print(f"medyan eklendi (kaynak: {kaynak}).")


